import sys
from typing import List

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def preorderTraversal(self, root: TreeNode) -> List[int]:
        if not root:
            return []
        result = []
        stack = [root]
        while stack:
            node = stack.pop()
            result.append(node.val)
            if node.right:
                stack.append(node.right)
            if node.left:
                stack.append(node.left)
        return result

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        nums = [int(next(it)) for _ in range(n)]
        root = None
        nodes = []
        for i in range(n):
            node = TreeNode(nums[i]) if nums[i] != -1 else None
            nodes.append(node)
        for i in range(n):
            left_idx = 2 * i + 1
            right_idx = 2 * i + 2
            if left_idx < n and nodes[i] and nodes[left_idx]:
                nodes[i].left = nodes[left_idx]
            if right_idx < n and nodes[i] and nodes[right_idx]:
                nodes[i].right = nodes[right_idx]
        root = nodes[0]
        sol = Solution()
        ans = sol.preorderTraversal(root)
        print(' '.join(map(str, ans)))
    except StopIteration:
        sys.exit(0)

