#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<int> preorderTraversal(TreeNode* root) {
        vector<int> result;
        if (!root) return result;
        stack<TreeNode*> stack;
        stack.push(root);
        while (!stack.empty()) {
            TreeNode* node = stack.top();
            stack.pop();
            result.push_back(node->val);
            if (node->right) stack.push(node->right);
            if (node->left) stack.push(node->left);
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    vector<TreeNode*> nodes(n);
    for (int i = 0; i < n; i++) {
        if (nums[i] != -1) nodes[i] = new TreeNode(nums[i]);
        else nodes[i] = nullptr;
    }
    for (int i = 0; i < n; i++) {
        int left_idx = 2 * i + 1;
        int right_idx = 2 * i + 2;
        if (left_idx < n && nodes[i] && nodes[left_idx]) nodes[i]->left = nodes[left_idx];
        if (right_idx < n && nodes[i] && nodes[right_idx]) nodes[i]->right = nodes[right_idx];
    }
    TreeNode* root = nodes[0];
    Solution sol;
    vector<int> ans = sol.preorderTraversal(root);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
